        <button
          key={f}
          onClick={() => setCommentFilter(f)}
          className={commentFilter === f ? 'active' : ''}
        >
          {f === 'pending' && 'Pendentes'}
          {f === 'approved' && 'Aprovados'}
          {f === 'rejected' && 'Rejeitados'}
          {f === 'all' && 'Todos'}
        </button>
      ))}
    </div>

    {comments.map((c) => (
      <div key={c.id} className="comment-card">
        <img src={c.author_photo_path} className="avatar" />
        <div>
          <strong>{c.author_name}</strong>
          <span>{'★'.repeat(c.rating)}</span>
          <p>{c.body}</p>
          <p>{new Date(c.created_at).toLocaleString('pt-BR')}</p>
        </div>

        {/* Ações */}
        {commentFilter === 'pending' && (
          <>
            <button onClick={() => moderate(c.id, 'approve')}>Aprovar</button>
            <button onClick={() => moderate(c.id, 'reject')}>Rejeitar</button>
          </>
        )}
        <button onClick={() => deleteComment(c.id)}>Excluir</button>
      </div>
    ))}
  </div>
)}
